insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('c1000000-0000-0000-0000-000000000004', 'child-development-fund', '兒童發展基金', 'Child Development Fund (CDF)', '勞工及福利局 / 社會福利署', 'family_child', '為弱勢社群兒童提供更多元化嘅發展機會，減少跨代貧窮。', '來自低收入家庭嘅兒童及青少年。', '透過個人發展規劃、師友配對及目標儲蓄，幫低收入家庭嘅兒童累積資產同拓寬視野。', '來自低收入家庭（如領綜援或全額學生資助）嘅指定年齡兒童。', '家庭收入超出資助界線，或年齡不符計劃要求嘅兒童。', '["一般對象為指定年齡（約 10–16 歲）嘅兒童（確實年齡以計劃為準）","來自低收入家庭，例如正領取綜援或全額書簿津貼／學生資助","由參與計劃嘅非政府機構營辦，須經該機構報名參加","須參與個人發展規劃、師友計劃及目標儲蓄"]'::jsonb, '以低收入家庭為對象（如綜援或全額學生資助），具體界線以計劃公布為準。', null, null, null, '指定年齡兒童（以計劃公布為準）。', null, null, '經參與計劃嘅非政府機構報名。', null, 'https://www.cdf.gov.hk/tc/', null, null, null, null, null, '3902 0201', null, 'https://www.cdf.gov.hk/tc/', 'https://www.cdf.gov.hk/tc/', '2026-07-08', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["low_income","student"]'::jsonb, '[{"order":1,"text":"第一步：睇下你屋企係咪低收入、小朋友年齡啱唔啱。"},{"order":2,"text":"第二步：搵營辦計劃嘅社福機構了解詳情。"},{"order":3,"text":"第三步：向機構報名參加。"},{"order":4,"text":"第四步：參與個人發展規劃、師友配對同目標儲蓄。"},{"order":5,"text":"第五步：完成計劃，累積到嘅儲蓄可用於發展目標。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人及兒童身份證明","required":true},{"key":"income_proof","label":"家庭入息證明或綜援 / 學生資助證明","required":true}]'::jsonb, '[{"name":"兒童發展基金頁面","type":"link","url":"https://www.cdf.gov.hk/tc/"}]'::jsonb, '[{"url":"https://www.cdf.gov.hk/tc/","title":"兒童發展基金 官方網站"}]'::jsonb, '[]'::jsonb, '[{"field":"on_cssa_or_full_grant","operator":"equals","value":true,"source_url":"https://www.cdf.gov.hk/tc/","confidence":"medium","needs_review":true}]'::jsonb, '["cssa-student-support"]'::jsonb, '["low_income"]'::jsonb, '{"meansTested":true}'::jsonb, '{"means_tested":true,"income_tested":true,"household_type":["low_income"],"tags":["child","family"]}'::jsonb, null) on conflict (id) do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('c1000000-0000-0000-0000-000000000004', 'low_income') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('eeeeeeee-eeee-eeee-eeee-eeeeeeeeeeee', 'community-care-service-voucher', '長者社區照顧服務券', 'Community Care Service Voucher for the Elderly (CCSV)', '社會福利署', 'rehab_community', '俾身體機能有中度或以上缺損嘅長者一張服務券，可以揀日間中心或上門嘅照顧服務。費用按家庭收入分擔。', '身體機能較弱、需要日間或家居照顧，想自己揀服務嘅長者。', '俾身體機能有中度或以上缺損嘅長者一張服務券，可以揀日間中心或上門嘅照顧服務。費用按家庭收入分擔。', '身體機能較弱、需要日間或家居照顧，想自己揀服務嘅長者。', '身體健壯、暫時唔需要照顧服務嘅長者。', '["經「安老服務統一評估機制」評估並建議接受社區照顧或院舍照顧服務","正在「中央輪候冊」輪候資助長期護理服務","現時並未接受任何院舍照顧或任何資助社區照顧服務","費用按家庭經濟狀況共同分擔","官方以評估結果及輪候狀況界定資格，並無單獨列明最低年齡；以社署為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/psccsv/', null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/psccsv/', 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/psccsv/', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["elderly","disability","low_income"]'::jsonb, '[{"order":1,"text":"第一步：睇下長者身體機能係咪需要照顧。"},{"order":2,"text":"第二步：搵社工安排「安老服務統一評估」。"},{"order":3,"text":"第三步：評估合資格就會編配服務券。"},{"order":4,"text":"第四步：揀一間認可服務單位用服務券。"},{"order":5,"text":"第五步：按家庭收入付返一部分費用。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"age_proof","label":"年齡證明（身份證）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"入息證明","required":true},{"key":"disability_proof","label":"殘疾 / 醫療證明","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/psccsv/"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/psccsv/","title":"長者社區照顧服務券 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["long_term_care"]'::jsonb, '{"requiresElderly":true,"minAgeBand":"65_69","meansTested":true,"maxIncomeBand":"30k_40k","medicalRelated":true,"boostLivingAlone":true}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":false,"age_min":65,"disability":true,"student":false,"elderly":true,"tags":["elderly","disability","low_income"]}'::jsonb, 'community_care_service_voucher.md') on conflict (id) do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('eeeeeeee-eeee-eeee-eeee-eeeeeeeeeeee', 'long_term_care') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('c1000000-0000-0000-0000-000000000001', 'continuing-education-fund', '持續進修基金', 'Continuing Education Fund (CEF)', '在學資助處 · 持續進修基金辦事處（WFSFAA）', 'adult_learning', '資助合資格人士修讀合資格嘅持續進修及培訓課程嘅部分學費。', '想進修增值嘅成年香港居民。', '政府資助成年人進修，發還部分課程學費，設終身資助上限（金額以官方為準）。', '年滿 18 歲、想報讀合資格持續進修課程嘅香港居民。', '所報讀課程並非「合資格課程資料網」載列嘅合資格課程。', '["年滿 18 歲並持有效香港身份證","報讀「合資格課程資料網」載列嘅合資格課程","須符合課程出席率及評核要求方可申請發還款項","設終身資助上限（金額及發還比例以官方最新公布為準）"]'::jsonb, '毋須入息審查（非經濟審查資助）。', '須為香港居民（詳情以官方為準）。', null, null, '年滿 18 歲。', null, null, '完成課程後向持續進修基金辦事處申請發還款項。', null, 'https://www.wfsfaa.gov.hk/cef/tc/index.htm', null, null, null, null, null, '3142 2277', null, 'https://www.wfsfaa.gov.hk/cef/tc/index.htm', 'https://www.wfsfaa.gov.hk/cef/tc/index.htm', '2026-07-08', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["other"]'::jsonb, '[{"order":1,"text":"第一步：睇下你想讀嘅課程係咪合資格課程。"},{"order":2,"text":"第二步：報讀並完成課程，保留學費收據同成績。"},{"order":3,"text":"第三步：喺限期內遞交發還款項申請。"},{"order":4,"text":"第四步：等基金辦事處審核。"},{"order":5,"text":"第五步：批咗會發還部分學費。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true}]'::jsonb, '[{"name":"持續進修基金頁面","type":"link","url":"https://www.wfsfaa.gov.hk/cef/tc/index.htm"}]'::jsonb, '[{"url":"https://www.wfsfaa.gov.hk/cef/tc/index.htm","title":"持續進修基金 官方頁面"}]'::jsonb, '[]'::jsonb, '[{"field":"age","operator":"gte","value":18,"source_url":"https://www.wfsfaa.gov.hk/cef/tc/index.htm","confidence":"medium","needs_review":true}]'::jsonb, '[]'::jsonb, '["adult_study","job_seeking"]'::jsonb, '{"meansTested":false}'::jsonb, '{"means_tested":false,"age_min":18,"tags":["adult_learning"]}'::jsonb, null) on conflict (id) do nothing;
