insert into public.benefit_life_events (benefit_id, life_event_code) values ('c1000000-0000-0000-0000-000000000001', 'job_seeking') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-00000000000b', 'criminal-law-enforcement-injuries-compensation', '暴力及執法傷亡賠償計劃', 'Criminal and Law Enforcement Injuries Compensation Scheme (CLEIC)', '社會福利署（社會保障）', 'social_security', '為因暴力罪行受傷，或因執法人員執行職務時使用武器而受傷嘅人士（或死亡個案嘅受養人）提供經濟援助（無須經濟審查）。', '因暴力罪行或執法人員執行職務使用武器而受傷嘅人士，或有關死者嘅受養人。', '暴力及執法傷亡賠償計劃（CLEIC）為因暴力罪行受傷、或因執法人員（值勤警務人員或其他公職人員）執行職務使用武器而受傷嘅人士（或死亡個案嘅受養人）提供經濟援助，屬「無須經濟審查」計劃。每宗申請須符合：事件曾進行刑事法律程序，或已在無不合理延誤下向警方報案；傷者於事件發生時合法獲准留港；於事件發生後 3 年內提出申請；並因事件死亡、永久傷殘，或所受傷勢經註冊醫生 / 註冊中醫師證明須住院或病假不少於 3 天。', '因暴力罪行或執法使用武器受傷嘅人士，或有關死者受養人（無須經濟審查）。', '未曾報案 / 無刑事程序、逾 3 年申請期、事件發生時非合法留港，或傷勢未達門檻者。', '["受傷須因暴力罪行，或因執法人員（值勤警務人員或其他公職人員）執行職務時使用武器所致","事件曾成為刑事法律程序主題，或已在無不合理延誤下向警方報案","傷者於事件發生時須合法獲准留港","須於事件發生後 3 年內提出申請","傷者因事件死亡或永久傷殘；或傷勢經註冊醫生 / 註冊中醫師證明須住院或病假不少於 3 天","屬「無須經濟審查」計劃","⚠️ Needs Manual Review：賠償金額及各項細則以社會福利署最新公布為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.sssof.swd.gov.hk/eForm/eApplyCLEIC/Start?lang=en_US', null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/en/pubsvc/socsecu/criminalan/', 'https://www.swd.gov.hk/en/pubsvc/socsecu/criminalan/', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["other","disability"]'::jsonb, '[{"order":1,"text":"第一步：確認事件已報案或有刑事程序，並在 3 年申請期內。"},{"order":2,"text":"第二步：準備醫生／中醫證明及報案證明。"},{"order":3,"text":"第三步：於社署網頁下載並填妥 CLEIC 申請表（或用網上表格）。"},{"order":4,"text":"第四步：將申請交予暴力及執法傷亡賠償組（CLEIC Section）。"},{"order":5,"text":"第五步：接受審核，批核後領取賠償。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"label":"醫生 / 中醫證明書（住院或病假證明）","required":true},{"label":"報案 / 刑事程序證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"CLEIC 網上申請表","type":"link","url":"https://www.sssof.swd.gov.hk/eForm/eApplyCLEIC/Start?lang=en_US"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/en/pubsvc/socsecu/criminalan/","title":"暴力及執法傷亡賠償計劃（官方頁面）","titleZh":"暴力及執法傷亡賠償計劃","titleEn":"Criminal and Law Enforcement Injuries Compensation Scheme","publisher":"Social Welfare Department","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.swd.gov.hk/en/pubsvc/socsecu/ss_info/quickfind/qf_cleics/qf_cleics_ec/index.html","title":"CLEIC — 資格準則（官方頁面）","titleZh":"暴力及執法傷亡賠償計劃 — 資格準則","titleEn":"CLEIC — Eligibility Criteria","publisher":"Social Welfare Department","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.sssof.swd.gov.hk/eForm/eApplyCLEIC/Start?lang=en_US","title":"CLEIC 網上申請表（官方申請頁面）","titleZh":"暴力及執法傷亡賠償計劃 網上申請表","titleEn":"CLEIC Application Form","publisher":"Social Welfare Department","sourceType":"application_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["traffic-accident-victims-assistance","disability-allowance"]'::jsonb, '["hospital_discharge","disability_diagnosed"]'::jsonb, '{"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"disability":true,"student":false,"elderly":false,"tags":["social_security","injury","compensation","non_means_tested"]}'::jsonb, null) on conflict (id) do nothing;
