insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-000000000005', 'cssa-scheme', '綜合社會保障援助（綜援）計劃', 'Comprehensive Social Security Assistance (CSSA) Scheme', '社會福利署（社會保障）', 'social_security', '透過入息及資產審查嘅現金援助，為經濟上無法自給嘅個人及家庭提供安全網，應付生活基本需要。', '香港居民中，個人或家庭經濟上無法自給、並通過入息及資產審查者（包括長者、殘疾人士、單親、失業、低收入等）。', '綜合社會保障援助（綜援）計劃以入息及資產審查方式，為經濟上無法自給嘅個人及家庭提供現金援助，應付生活基本需要。援助一般包括標準金額（按不同類別，如長者、殘疾、健全成人及兒童）、各項補助金及特別津貼。與家人同住者須以「住戶」為單位申請，計算全部家庭成員嘅入息及資產。', '經濟上無法自給、通過入息及資產審查嘅香港居民及其家庭。', '受《入境規例》第 115A 章逗留條件限制人士（如輸入勞工、訪客）不合資格；資產或入息超出上限者。', '["須符合居港規定（一般申請人須符合居港年期要求；未滿 18 歲嘅香港居民獲豁免居港規定）","須同時通過入息審查及資產審查","與其他家庭成員同住者，須以「住戶」為單位申請，計算全部同住家庭成員嘅入息及資產","受《入境規例》（第 115A 章）逗留條件限制人士（例如輸入勞工、訪客）不合資格","在特殊情況下，社會福利署署長可酌情向未符合居港規定人士批出綜援","援助包括標準金額、補助金及特別津貼等（實際金額按類別及個別情況而定）","⚠️ Needs Manual Review：各類標準金額、補助金、特別津貼、入息及資產限額每年調整，以官方最新公布為準"]'::jsonb, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/en/pubsvc/socsecu/comprehens/cssa/', 'https://www.swd.gov.hk/en/pubsvc/socsecu/comprehens/cssa/', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["low_income","elderly","disability"]'::jsonb, '[{"order":1,"text":"第一步：初步了解你 / 你嘅住戶入息及資產是否可能通過審查。"},{"order":2,"text":"第二步：準備所有同住家庭成員嘅身份證、住址、入息及資產證明。"},{"order":3,"text":"第三步：聯絡居住地區嘅社會保障辦事處（可電話、傳真、電郵、郵寄、網上表格或親身）遞交申請。"},{"order":4,"text":"第四步：接受入息及資產審查及面談（如需要）。"},{"order":5,"text":"第五步：批核後按月領取援助金。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人及同住家庭成員身份證","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"住戶入息證明","required":true},{"key":"asset_proof","label":"資產證明（銀行結單等）","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[]'::jsonb, '[{"url":"https://www.swd.gov.hk/en/pubsvc/socsecu/comprehens/cssa/","title":"綜合社會保障援助（綜援）計劃（官方頁面）","titleZh":"綜合社會保障援助（綜援）計劃","titleEn":"Comprehensive Social Security Assistance (CSSA) Scheme","publisher":"Social Welfare Department","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.swd.gov.hk/en/pubsvc/socsecu/comprehens/cssa/cssa_ec/cssa_ec_rr/index.html","title":"綜援 — 居港規定（官方頁面）","titleZh":"綜援 — 居港規定","titleEn":"CSSA — Residence Requirement","publisher":"Social Welfare Department","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.swd.gov.hk/storage/asset/section/179/en/CSSAG102023(Eng).pdf","title":"綜援計劃指南（官方指引）","titleZh":"綜合社會保障援助計劃指南","titleEn":"A Guide to Comprehensive Social Security Assistance","publisher":"Social Welfare Department","sourceType":"guidance_note","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["working-family-allowance","cssa-student-support"]'::jsonb, '["low_income","unemployed","single_parent"]'::jsonb, '{"meansTested":true,"maxIncomeBand":"below_10k","maxAssetBand":"low"}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":true,"disability":false,"student":false,"elderly":false,"tags":["social_security","low_income","safety_net"]}'::jsonb, null) on conflict (id) do nothing;
