insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('55555555-5555-5555-5555-555555555555', 'cssa-student-support', '綜援學生相關支援', 'Comprehensive Social Security Assistance (Student-related)', '社會福利署', 'social_security', '已領取綜援嘅家庭，子女讀書嘅學習津貼通常已經包喺綜援度，毋須另外申請書簿等津貼。', '正領取綜援、有在學子女嘅家庭。', '已領取綜援嘅家庭，子女讀書嘅學習津貼通常已經包喺綜援度，毋須另外申請書簿等津貼。', '正領取綜援、有在學子女嘅家庭。', '未領取綜援嘅家庭（應改為申請學生資助計劃）。', '["家庭正領取綜合社會保障援助（綜援）","符合居港規定（一般須成為香港居民滿 1 年及居港滿 1 年；未滿 18 歲人士可獲豁免）","通過入息及資產審查（以整個住戶為單位計算）","有就讀由幼兒中心至中學嘅在學子女","學校相關開支（書簿、車船、上網費、就學津貼等）由社署按綜援個案發放","綜援家庭毋須（亦不可）就同一項目另向學生資助處申請"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.swd.gov.hk/tc/pubsvc/socsecu/comprehens/cssa/', null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/tc/pubsvc/socsecu/comprehens/cssa/', 'https://www.swd.gov.hk/tc/pubsvc/socsecu/comprehens/cssa/', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["low_income","student"]'::jsonb, '[{"order":1,"text":"第一步：確認你屋企正領緊綜援。"},{"order":2,"text":"第二步：準備綜援文件、學生證明、身份證。"},{"order":3,"text":"第三步：向你個案嘅社會保障部職員講有在學子女。"},{"order":4,"text":"第四步：交學生相關證明俾社會福利署。"},{"order":5,"text":"第五步：學習津貼會隨綜援一齊發放。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"student_id","label":"學生身份證 / 出世紙","required":true},{"key":"student_proof","label":"學生證明（學校信 / 收生紙）","required":true},{"key":"cssa_proof","label":"綜援證明（如適用）","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.swd.gov.hk/tc/pubsvc/socsecu/comprehens/cssa/"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/tc/pubsvc/socsecu/comprehens/cssa/","title":"綜援學生相關支援 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["low_income","unemployed","single_parent"]'::jsonb, '{"requiresCssa":true,"boostSen":true,"boostSingleParent":true}'::jsonb, '{"means_tested":true,"income_tested":false,"asset_tested":false,"age_min":null,"disability":false,"student":true,"elderly":false,"tags":["low_income","student"]}'::jsonb, 'cssa_student_support.md') on conflict (id) do nothing;
