insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', 'disability-allowance', '傷殘津貼', 'Disability Allowance', '社會福利署（社會保障）', 'disability', '俾經評估為嚴重殘疾嘅香港居民嘅每月現金津貼，唔使入息審查。分普通同高額兩種。', '經醫生評估為嚴重殘疾嘅人士（任何年齡）。', '俾經評估為嚴重殘疾嘅香港居民嘅每月現金津貼，唔使入息審查。分普通同高額兩種。', '經醫生評估為嚴重殘疾嘅人士（任何年齡）。', '未經評估、或殘疾程度未達標準嘅人士。', '["經衞生署署長或醫院管理局行政總裁證明為「嚴重殘疾」（傷殘情況預計持續最少 6 個月）","成為香港居民滿 7 年並在申請前連續居港滿 1 年（未滿 18 歲申請人可獲豁免居港年期規定）","毋須入息或資產審查（免審查）","並非同時領取其他社會保障津貼或綜援","高額傷殘津貼：另須經證明日常生活需要他人經常照顧，且並非在受資助院舍／公立醫院等接受照顧","領款期間須繼續居於香港；被羈押或入住懲教院所期間不可領取"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssa_app/index.html', null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssaec/ssaec_nda/index.html', 'https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssaec/ssaec_nda/index.html', '2026-06-01', 'verified', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["disability"]'::jsonb, '[{"order":1,"text":"第一步：搵醫生做殘疾評估。"},{"order":2,"text":"第二步：準備身份證、住址證明同醫生證明。"},{"order":3,"text":"第三步：填傷殘津貼申請表。"},{"order":4,"text":"第四步：交俾社會福利署。"},{"order":5,"text":"第五步：批咗會每月過錢入你戶口。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"disability_proof","label":"殘疾 / 醫療證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssa_app/index.html"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssaec/ssaec_nda/index.html","title":"傷殘津貼 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["disability_diagnosed"]'::jsonb, '{"requiresDisability":true,"meansTested":false,"boostLivingAlone":true}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":null,"disability":true,"student":false,"elderly":false,"tags":["disability"]}'::jsonb, 'disability_allowance.md') on conflict (id) do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa', 'disability_diagnosed') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('b2b2b2b2-b2b2-b2b2-b2b2-b2b2b2b2b2b2', 'elderly-dental-assistance', '長者牙科服務資助計劃', 'Elderly Dental Assistance Programme', '社會福利署（關愛基金資助）', 'healthcare', '幫合資格長者免費或資助鑲牙同相關牙科治療，等佢哋食嘢同健康好啲。', '有需要脫牙、鑲牙，又正接受指定長者服務嘅長者。', '幫合資格長者免費或資助鑲牙同相關牙科治療，等佢哋食嘢同健康好啲。', '有需要脫牙、鑲牙，又正接受指定長者服務嘅長者。', '毋須牙科治療、或未符合指定服務條件嘅人士。', '["低收入長者，並符合其中一項：正領取長者生活津貼（即 65 歲或以上）；或屬社署資助家居照顧服務（IHCS／EHCCS）中收費第一或第二級別嘅使用者","並非正領取綜援，亦未曾受惠於「長者牙科外展服務」","每名合資格長者最多可接受服務兩次；第二次須年滿 75 歲且過去 5 年內未曾受惠","由指定服務單位安排申請","計劃由關愛基金資助；名額及詳情以官方為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.communitycarefund.hk/', null, null, null, null, null, '2343 2255', null, 'https://www.communitycarefund.hk/', 'https://www.communitycarefund.hk/', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["elderly","low_income"]'::jsonb, '[{"order":1,"text":"第一步：睇下你係咪正用緊指定長者服務。"},{"order":2,"text":"第二步：向服務單位或社工查詢牙科資助。"},{"order":3,"text":"第三步：填申請表，安排牙科檢查。"},{"order":4,"text":"第四步：由認可牙醫提供鑲牙等治療。"},{"order":5,"text":"第五步：資助會直接減免治療費用。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"age_proof","label":"年齡證明（身份證）","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.communitycarefund.hk/"}]'::jsonb, '[{"url":"https://www.communitycarefund.hk/","title":"長者牙科服務資助計劃 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["retirement","low_income"]'::jsonb, '{"requiresElderly":true,"minAgeBand":"65_69","medicalRelated":true,"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":65,"disability":false,"student":false,"elderly":true,"tags":["elderly","low_income"]}'::jsonb, 'elderly_dental_assistance.md') on conflict (id) do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('b2b2b2b2-b2b2-b2b2-b2b2-b2b2b2b2b2b2', 'retirement') on conflict do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('b2b2b2b2-b2b2-b2b2-b2b2-b2b2b2b2b2b2', 'low_income') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('99999999-9999-9999-9999-999999999999', 'elderly-health-care-voucher', '長者醫療券', 'Elderly Health Care Voucher Scheme', '衞生署（醫療券計劃）', 'healthcare', '俾 65 歲或以上長者用嚟睇私家醫生、牙醫、中醫等基層醫療服務嘅醫療券。每年金額由政府公布。', '65 歲或以上、想睇私家基層醫療嘅長者。', '俾 65 歲或以上長者用嚟睇私家醫生、牙醫、中醫等基層醫療服務嘅醫療券。每年金額由政府公布。', '65 歲或以上、想睇私家基層醫療嘅長者。', '未夠 65 歲嘅人士。', '["年滿 65 歲","持有效香港身份證，或入境事務處簽發嘅有效豁免登記證明書","毋須入息或資產審查，亦無居港年期要求（非永久居民持有效證件亦合資格）","領取綜援或傷殘津貼人士仍可使用醫療券","憑年齡自動建立醫療券戶口，一般毋須另行申請","曾以已失效逗留許可取得香港身份證者不合資格"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.hcv.gov.hk/tc/hcvs/target_group.html', null, null, null, null, null, '2838 2311', null, 'https://www.hcv.gov.hk/tc/hcvs/background.html', 'https://www.hcv.gov.hk/tc/hcvs/background.html', '2026-06-01', 'verified', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["elderly"]'::jsonb, '[{"order":1,"text":"第一步：睇下你係咪夠 65 歲。"},{"order":2,"text":"第二步：帶身份證去睇已登記嘅醫生或牙醫。"},{"order":3,"text":"第三步：睇醫生時話用醫療券找數。"},{"order":4,"text":"第四步：系統會自動喺你戶口扣醫療券。"},{"order":5,"text":"第五步：唔使另外攞現金，直接抵扣診金。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"age_proof","label":"年齡證明（身份證）","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.hcv.gov.hk/tc/hcvs/target_group.html"}]'::jsonb, '[{"url":"https://www.hcv.gov.hk/tc/hcvs/background.html","title":"長者醫療券 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["retirement"]'::jsonb, '{"requiresElderly":true,"minAgeBand":"65_69","medicalRelated":true,"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":65,"disability":false,"student":false,"elderly":true,"tags":["elderly"]}'::jsonb, 'elderly_health_care_voucher.md') on conflict (id) do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('99999999-9999-9999-9999-999999999999', 'retirement') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-000000000004', 'employment-programme-elderly-middle-aged', '中高齡就業計劃', 'Employment Programme for the Elderly and Middle-aged (EPEM)', '勞工處', 'employment', '鼓勵僱主聘用 40 歲或以上求職人士並提供在職培訓（OJT），協助中高齡人士就業。在職培訓津貼由勞工處發放予僱主；求職人士則透過受僱及培訓受惠。', '40 歲或以上、正在求職嘅中高齡人士；以及願意聘用及培訓佢哋嘅僱主。', '中高齡就業計劃（EPEM）由勞工處推行，鼓勵僱主聘用 40 歲或以上求職人士並提供在職培訓。津貼發放對象為僱主：聘用每名 60 歲或以上、失業或已離開職場嘅求職者，僱主可獲最高每月 $5,000、為期 6 至 12 個月嘅在職培訓津貼；聘用每名 40 至 59 歲失業求職者，可獲最高每月 $4,000、為期 3 至 6 個月。計劃涵蓋全職及兼職職位。', '40 歲或以上正在求職嘅人士（透過受僱及在職培訓受惠）；有意聘用中高齡員工嘅僱主。', '在職培訓津貼並非直接發放予求職人士，而係發放予符合條件嘅僱主；40 歲以下人士。', '["求職人士須年滿 40 歲或以上","僱主聘用每名 40 至 59 歲失業求職者：最高每月 $4,000 在職培訓津貼，為期 3 至 6 個月","僱主聘用每名 60 歲或以上失業／已離開職場求職者：最高每月 $5,000 在職培訓津貼，為期 6 至 12 個月","在職培訓期經勞工處批准，個別合適個案可分別延長至最多 6 個月及 12 個月","計劃涵蓋全職及兼職職位","⚠️ Needs Manual Review：津貼金額、培訓期、僱主及僱員資格條件以勞工處最新公布為準"]'::jsonb, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, '2969 0888', null, 'https://www.labour.gov.hk/eng/service/content.htm', 'https://www.labour.gov.hk/eng/public/pdf/eip/EPM_ER.pdf', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["other"]'::jsonb, '[{"order":1,"text":"第一步：40 歲或以上求職人士可透過勞工處就業中心 / 互動就業服務登記求職。"},{"order":2,"text":"第二步：經勞工處配對合適職位（包括參與 EPEM 嘅僱主職位）。"},{"order":3,"text":"第三步：獲聘後由僱主提供在職培訓；僱主向勞工處申領在職培訓津貼。"},{"order":4,"text":"第四步：完成培訓期，穩定就業。"}]'::jsonb, '[{"key":"applicant_id","label":"求職人士身份證","required":true}]'::jsonb, '[]'::jsonb, '[{"url":"https://www.labour.gov.hk/eng/public/pdf/eip/EPM_ER.pdf","title":"中高齡就業計劃 — 僱主資料（官方單張）","titleZh":"中高齡就業計劃 — 僱主須知","titleEn":"Employment Programme for the Elderly and Middle-aged — For Employers","publisher":"Labour Department","sourceType":"guidance_note","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.labour.gov.hk/eng/service/content.htm","title":"勞工處 — 就業服務（官方頁面）","titleZh":"勞工處 — 就業服務","titleEn":"Labour Department — Employment Services","publisher":"Labour Department","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["erb-training"]'::jsonb, '["job_seeking","unemployed"]'::jsonb, '{"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":40,"disability":false,"student":false,"elderly":false,"tags":["employment","middle_aged","elderly","job_seeking"]}'::jsonb, null) on conflict (id) do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('d2000000-0000-0000-0000-000000000004', 'job_seeking') on conflict do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('d2000000-0000-0000-0000-000000000004', 'unemployed') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('c1000000-0000-0000-0000-000000000003', 'erb-training', '僱員再培訓局課程', 'Employees Retraining Board (ERB) Training Courses', '僱員再培訓局（ERB）', 'employment', '為有需要人士提供職業技能培訓及就業支援，協助就業或轉業。', '想學技能、搵工或轉工嘅成年香港居民。', '提供多元職業培訓課程（就業掛鈎及非就業掛鈎），部分課程設培訓津貼及就業跟進服務。', '15 歲或以上、副學位或以下學歷、想增值或搵工嘅香港居民。', '學歷或身分不符合個別課程要求嘅人士。', '["一般為年滿 15 歲、具副學位或以下學歷嘅香港居民","提供就業掛鈎（設出席及就業要求）及非就業掛鈎課程","部分全日制就業掛鈎課程設培訓津貼","個別課程嘅入讀資格、學費減免及津貼安排以僱員再培訓局公布為準"]'::jsonb, '一般毋須入息審查；個別津貼或有特定條件（以官方為準）。', null, null, null, '一般年滿 15 歲。', null, '副學位或以下學歷（個別課程另有要求）。', '向 ERB 委任嘅培訓機構報名。', null, 'https://www.erb.org/tc/', null, null, null, null, null, '182 182', null, 'https://www.erb.org/tc/', 'https://www.erb.org/tc/', '2026-07-08', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["other","low_income"]'::jsonb, '[{"order":1,"text":"第一步：喺 ERB 課程一覽揀啱你嘅課程。"},{"order":2,"text":"第二步：確認入讀資格同上課地點。"},{"order":3,"text":"第三步：向培訓機構報名。"},{"order":4,"text":"第四步：完成課程，達到出席及評核要求。"},{"order":5,"text":"第五步：就業掛鈎課程可獲就業跟進及（如適用）培訓津貼。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true}]'::jsonb, '[{"name":"ERB 課程一覽","type":"link","url":"https://www.erb.org/tc/"}]'::jsonb, '[{"url":"https://www.erb.org/tc/","title":"僱員再培訓局 官方網站"}]'::jsonb, '[]'::jsonb, '[{"field":"age","operator":"gte","value":15,"source_url":"https://www.erb.org/tc/","confidence":"medium","needs_review":true}]'::jsonb, '["working-family-allowance"]'::jsonb, '["job_seeking","unemployed","adult_study"]'::jsonb, '{"meansTested":false}'::jsonb, '{"means_tested":false,"age_min":15,"employment_status":["unemployed","job_seeking","employed"],"tags":["employment","adult_learning"]}'::jsonb, null) on conflict (id) do nothing;
