insert into public.benefit_life_events (benefit_id, life_event_code) values ('c1000000-0000-0000-0000-000000000003', 'unemployed') on conflict do nothing;
insert into public.benefit_life_events (benefit_id, life_event_code) values ('c1000000-0000-0000-0000-000000000003', 'adult_study') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-00000000000a', 'fasp-postsecondary', '專上學生資助計劃', 'Financial Assistance Scheme for Post-secondary Students (FASP)', '在職家庭及學生資助事務處（學生資助處）', 'postsecondary', '為修讀本地認可、自資專上課程（副學位或學位程度）嘅全日制學生提供入息審查資助（助學金及／或貸款）。', '修讀本地認可自資副學士 / 高級文憑 / 學士課程、並通過入息及資產審查嘅全日制學生。', '專上學生資助計劃（FASP）以入息審查方式，向修讀本地認可、自資專上課程（副學士、高級文憑或學士學位程度）嘅全日制學生提供助學金及／或貸款。資助水平由「入息審查」及「資產審查」兩層審查決定，按相應百分比計算最高助學金及貸款額。與資助專上課程（TSFS）不同：FASP 對象係自資課程學生。', '修讀本地認可自資副學位 / 學位全日制課程、家庭入息及資產通過審查嘅學生。', '修讀公帑資助課程者（應用 TSFS）；同一學年就同一課程已接受其他公帑資助學生資助者；未符合居港年期者。', '["修讀本地認可、自資嘅全日制專上課程（副學士 / 高級文憑等副學位，或學士學位程度）","「全日制」：面授課程每年不少於 450 課堂時數，或每年最少 30 學分（1 學分＝15 課堂時數）；非面授課程每年不少於 1,350 學習時數","須擁有香港居留權，或在課程開始前已連續居港滿三整年","同一學年就申請所涵蓋嘅課程，不得已接受其他公帑資助學生資助計劃嘅資助","資助額由「入息審查」及「資產審查」兩層means test 決定","⚠️ Needs Manual Review：每學年最高助學金 / 貸款額及審查機制以官方「資助額」頁面為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.wfsfaa.gov.hk/en/sfo/postsecondary/fasp/forms.php', null, null, null, null, null, '2152 9000', null, 'https://www.wfsfaa.gov.hk/en/sfo/postsecondary/fasp/overview.php', 'https://www.wfsfaa.gov.hk/en/sfo/postsecondary/fasp/overview.php', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["student","low_income"]'::jsonb, '[{"order":1,"text":"第一步：確認你修讀嘅係本地認可自資全日制專上課程。"},{"order":2,"text":"第二步：準備身份證、課程證明、家庭入息及資產資料。"},{"order":3,"text":"第三步：向學生資助處遞交 FASP 申請。"},{"order":4,"text":"第四步：接受兩層入息及資產審查（一般於學生資助處確認收妥申請後約 2 個月內獲通知結果）。"},{"order":5,"text":"第五步：批出後領取助學金及／或貸款。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"student_proof","label":"自資課程學生身份 / 課程證明","required":true},{"key":"income_proof","label":"家庭成員入息證明","required":true},{"key":"asset_proof","label":"資產證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"FASP 申請連結、表格及下載","type":"link","url":"https://www.wfsfaa.gov.hk/en/sfo/postsecondary/fasp/forms.php"}]'::jsonb, '[{"url":"https://www.wfsfaa.gov.hk/en/sfo/postsecondary/fasp/overview.php","title":"FASP 概覽（官方頁面）","titleZh":"專上學生資助計劃 — 概覽","titleEn":"FASP — Overview","publisher":"Working Family and Student Financial Assistance Agency","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.wfsfaa.gov.hk/en/sfo/postsecondary/fasp/eligibility.php","title":"FASP 申請資格（官方頁面）","titleZh":"專上學生資助計劃 — 申請資格","titleEn":"FASP — Eligibility","publisher":"Working Family and Student Financial Assistance Agency","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.wfsfaa.gov.hk/en/sfo/postsecondary/fasp/level.php","title":"FASP 資助額（官方頁面）","titleZh":"專上學生資助計劃 — 資助額","titleEn":"FASP — Level of Financial Assistance","publisher":"Working Family and Student Financial Assistance Agency","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["tsfs-postsecondary","nlsft-tertiary-loan"]'::jsonb, '["university","adult_study","low_income"]'::jsonb, '{"meansTested":true,"maxIncomeBand":"20k_30k"}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":true,"disability":false,"student":true,"elderly":false,"tags":["student","postsecondary","self_financing","low_income"]}'::jsonb, null) on conflict (id) do nothing;
