insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-000000000008', 'home-ownership-scheme', '居者有其屋計劃', 'Home Ownership Scheme (HOS)', '香港房屋委員會', 'housing', '由香港房屋委員會以低於市值嘅價格，出售資助出售單位（居屋），協助綠表及白表合資格人士置業。', '符合綠表（如公屋住戶）或白表（如私樓住戶、家庭入息及資產在限額內）資格、有意置業嘅人士及家庭。', '居者有其屋計劃（HOS）由香港房屋委員會推出，以低於市值價格出售資助出售單位。申請分「綠表」及「白表」兩類：綠表包括房委會公屋住戶、房協甲類出租屋邨住戶，以及持有效「綠表資格證明書」人士；白表包括居於私人樓宇人士、公屋／房協出租屋邨住戶嘅家庭成員，以及購入未滿 10 年嘅租者置其屋計劃單位業主。有關年齡、家庭組合、居港規定、入息及資產限額、業主權限制等詳細條件，由房委會在每次銷售計劃前公布。', '符合綠表或白表資格、有意以資助價置業嘅人士及家庭。', '不符合綠表 / 白表資格、或入息／資產超出白表限額、或擁有其他物業（視乎銷售計劃限制）嘅申請人。', '["綠表申請人：包括房委會公屋住戶、房協甲類出租屋邨住戶，及持有效「綠表資格證明書（只適用於購買居屋）」人士","白表申請人：包括居於私人樓宇人士、房委會公屋 / 房協出租屋邨住戶嘅家庭成員，及購入未滿 10 年嘅租者置其屋計劃（TPS）單位業主","白表設有家庭入息及資產限額（每次銷售計劃前由房委會公布）","詳細年齡、家庭組合、居港規定、入息 / 資產限額及物業擁有權限制，由房委會在每次銷售計劃前公布","設有「家有長者優先選樓計劃」及「家有初生優先揀樓計劃」等優先安排及名額","⚠️ Needs Manual Review：每期銷售計劃嘅入息 / 資產限額、售價、名額及揀樓安排以房委會該期公布為準"]'::jsonb, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, 'https://www.housingauthority.gov.hk/en/home-ownership/hos-flats/eligibility/index.html', 'https://www.housingauthority.gov.hk/en/home-ownership/hos-flats/eligibility/index.html', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["low_income","other"]'::jsonb, '[{"order":1,"text":"第一步：確認你屬綠表定白表申請人。"},{"order":2,"text":"第二步：留意房委會公布嘅居屋銷售計劃（HOS）及申請期。"},{"order":3,"text":"第三步：按該期公布嘅入息 / 資產限額及條件遞交申請。"},{"order":4,"text":"第四步：抽籤 / 排序後按次序揀樓。"},{"order":5,"text":"第五步：完成買賣手續，注意轉售限制及補價安排。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人及家庭成員身份證","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"家庭入息證明（白表）","required":true},{"key":"asset_proof","label":"資產證明（白表）","required":true}]'::jsonb, '[]'::jsonb, '[{"url":"https://www.housingauthority.gov.hk/en/home-ownership/hos-flats/eligibility/index.html","title":"居屋 — 申請資格（官方頁面）","titleZh":"居者有其屋計劃 — 申請資格","titleEn":"Home Ownership Scheme — Eligibility","publisher":"Hong Kong Housing Authority","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.housingauthority.gov.hk/en/common/pdf/about-us/policy-focus/policies-on-public-housing/A06/A06.pdf","title":"公共房屋政策 — 第 6 章：居者有其屋計劃（官方政策文件）","titleZh":"公共房屋政策 — 第六章：居者有其屋計劃","titleEn":"Policies on Public Housing — Chapter 6: Home Ownership Scheme","publisher":"Hong Kong Housing Authority","sourceType":"guidance_note","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["public-rental-housing"]'::jsonb, '["first_home","public_housing"]'::jsonb, '{"meansTested":true}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":true,"disability":false,"student":false,"elderly":false,"tags":["housing","home_ownership","subsidised_sale"]}'::jsonb, null) on conflict (id) do nothing;
