insert into public.benefit_life_events (benefit_id, life_event_code) values ('d2000000-0000-0000-0000-000000000008', 'public_housing') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'integrated-discharge-support-elderly', '離院長者綜合支援計劃（出院長者支援）', 'Integrated Discharge Support Programme for Elderly Patients (IDSP)', '社會福利署 / 醫院管理局', 'rehab_community', '長者出院後，喺屋企提供一段時間嘅過渡支援，例如家居照顧、復康、送飯、護理，幫佢哋順利返返屋企生活。', '啱啱喺醫院出院、返屋企後需要短期照顧或復康支援嘅長者。', '長者出院後，喺屋企提供一段時間嘅過渡支援，例如家居照顧、復康、送飯、護理，幫佢哋順利返返屋企生活。', '啱啱喺醫院出院、返屋企後需要短期照顧或復康支援嘅長者。', '毋須出院後照顧、或已入住院舍嘅長者。', '["為公立醫院嘅住院病人","年滿 60 歲","經醫院管理局「出院規劃小組」評估為出院後有較高非計劃再入院風險","不設入息審查，按臨床及照顧需要評估","由醫院、醫護或社工轉介，並無公開自行報名途徑"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/', null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/', 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["elderly","disability"]'::jsonb, '[{"order":1,"text":"第一步：喺醫院出院前，同醫護或社工講你需要返屋企照顧。"},{"order":2,"text":"第二步：醫院會評估你嘅需要，再轉介去計劃。"},{"order":3,"text":"第三步：負責機構會聯絡你，安排上門支援。"},{"order":4,"text":"第四步：喺屋企接受一段時間嘅照顧、復康或送飯。"},{"order":5,"text":"第五步：情況穩定後，會轉介去長期社區服務。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"age_proof","label":"年齡證明（身份證）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"disability_proof","label":"殘疾 / 醫療證明","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/","title":"離院長者綜合支援計劃（出院長者支援） 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["hospital_discharge","long_term_care"]'::jsonb, '{"requiresElderly":true,"minAgeBand":"60_64","medicalRelated":true,"meansTested":false,"boostLivingAlone":true}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":60,"disability":true,"student":false,"elderly":true,"tags":["elderly","disability"]}'::jsonb, 'integrated_discharge_support.md') on conflict (id) do nothing;
