insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('33333333-3333-3333-3333-333333333333', 'internet-access-subsidy', '上網費津貼計劃', 'Subsidy Scheme for Internet Access Charges', '在學資助處（學生資助處）', 'student_assistance', '幫有學生嘅低收入家庭，補貼部分屋企上網費，方便網上學習。', '屋企有學生、需要上網做功課或網上學習嘅低收入家庭。', '幫有學生嘅低收入家庭，補貼部分屋企上網費，方便網上學習。', '屋企有學生、需要上網做功課或網上學習嘅低收入家庭。', '家庭收入較高、或者已無在學子女嘅家庭。', '["家庭有全日制就讀中小學或以下（或指定專上以下課程）嘅子女","申請人為家長或監護人；學生為未婚香港居民並具香港居留身份","每戶一年一次定額津貼","家庭須通過入息審查（獲發全額或半額資格證明書）","並非正領取綜援（綜援家庭嘅上網費由社署支付，不可同年重複領取）","若已從其他公私營機構或學校獲上網費資助則不合資格"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/procedures.php', null, null, null, null, null, '2802 2345', null, 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/sia.php', 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/sia.php', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["student","low_income"]'::jsonb, '[{"order":1,"text":"第一步：睇下屋企有冇學生要上網學習。"},{"order":2,"text":"第二步：準備身份證、學生證明、住址證明、收入或綜援證明。"},{"order":3,"text":"第三步：填上網費津貼申請表。"},{"order":4,"text":"第四步：交俾學生資助處或指定機構。"},{"order":5,"text":"第五步：等通知，批咗會發放定額津貼。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"student_id","label":"學生身份證 / 出世紙","required":true},{"key":"student_proof","label":"學生證明（學校信 / 收生紙）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"入息證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/procedures.php"}]'::jsonb, '[{"url":"https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/sia.php","title":"上網費津貼計劃 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["kindergarten","primary_school","secondary_school","low_income"]'::jsonb, '{"gradeLevels":["kindergarten","primary","secondary"],"maxIncomeBand":"20k_30k","internetRelated":true,"boostNewArrival":true}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":false,"age_min":null,"disability":false,"student":true,"elderly":false,"tags":["student","low_income"]}'::jsonb, 'internet_subsidy.md') on conflict (id) do nothing;
