insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-000000000003', 'nlsft-tertiary-loan', '全日制大專學生免入息審查貸款計劃', 'Non-means-tested Loan Scheme for Full-time Tertiary Students (NLSFT)', '在職家庭及學生資助事務處（學生資助處）', 'postsecondary', '為修讀認可全日制專上課程嘅學生提供「免入息審查」貸款，用嚟繳付學費。與資助專上課程學生資助計劃（TSFS）互補。以全數成本收回方式運作，須付利息及行政費。', '修讀認可全日制公帑資助專上課程、需要貸款繳付學費、但不想或不需要接受入息審查嘅學生。', '全日制大專學生免入息審查貸款計劃（NLSFT）為合資格全日制專上課程學生提供免入息審查貸款以繳付學費，與 TSFS 互補。貸款以「全數成本收回」方式運作：借款人須按提取貸款時嘅適用利率繳付利息，並須就每份申請及每個貸款戶口每學年繳付行政費，直至貸款及利息全數清還。設有終身貸款上限（與 NLSPS 合併計算）。', '修讀認可全日制專上課程、需要學費貸款嘅學生（不設入息審查）。', '想申請助學金（不用還款）者應考慮 TSFS；未符合居港年期或註冊要求者。', '["須於相關學年（例：2026/27）註冊為認可院校全日制專上課程學生，並修讀完全由公帑資助嘅學額","須擁有香港特別行政區居留權，或在課程開始前已連續居港滿三整年","不設入息審查（Non-means-tested）","貸款額最高可達該學年應繳學費總額，但受 NLSFT 與 NLSPS 合併終身貸款上限限制","以「全數成本收回」運作：須繳付按提取時適用利率累計嘅利息","每份申請及每個貸款戶口每學年須繳付行政費，直至貸款及利息全數清還","⚠️ Needs Manual Review：每學年申請截止日期、利率、行政費及終身貸款上限以官方最新公布為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.wfsfaa.gov.hk/sfo/en/postsecondary/nlsft/application/forms.htm', null, null, null, null, null, '2152 9000', null, 'https://www.wfsfaa.gov.hk/en/sfo/postsecondary/nlsft/overview.php', 'https://www.wfsfaa.gov.hk/en/sfo/postsecondary/nlsft/overview.php', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["student","other"]'::jsonb, '[{"order":1,"text":"第一步：確認你係認可院校全日制公帑資助課程嘅註冊學生。"},{"order":2,"text":"第二步：睇清楚利息、行政費同終身貸款上限等條款。"},{"order":3,"text":"第三步：於學生資助處遞交 NLSFT 申請（留意每學年截止日期）。"},{"order":4,"text":"第四步：等候批核及提取貸款繳付學費。"},{"order":5,"text":"第五步：按計劃還款，直至貸款及利息全數清還。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"student_proof","label":"學生身份 / 課程註冊證明","required":true},{"key":"address_proof","label":"住址 / 居港年期證明（如適用）","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"NLSFT 申請連結、表格及下載","type":"link","url":"https://www.wfsfaa.gov.hk/sfo/en/postsecondary/nlsft/application/forms.htm"}]'::jsonb, '[{"url":"https://www.wfsfaa.gov.hk/en/sfo/postsecondary/nlsft/overview.php","title":"NLSFT 概覽（官方頁面）","titleZh":"全日制大專學生免入息審查貸款計劃 — 概覽","titleEn":"NLSFT — Overview","publisher":"Working Family and Student Financial Assistance Agency","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.wfsfaa.gov.hk/en/sfo/postsecondary/nlsft/eligibility.php","title":"NLSFT 申請資格（官方頁面）","titleZh":"全日制大專學生免入息審查貸款計劃 — 申請資格","titleEn":"NLSFT — Eligibility","publisher":"Working Family and Student Financial Assistance Agency","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.wfsfaa.gov.hk/sfo/en/postsecondary/nlsft/general/loan_limit.htm","title":"NLSFT 最高貸款額及終身貸款上限（官方頁面）","titleZh":"全日制大專學生免入息審查貸款計劃 — 最高貸款額及終身貸款上限","titleEn":"NLSFT — Maximum Level of Loan Amount and Life-time Loan Limit","publisher":"Working Family and Student Financial Assistance Agency","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["tsfs-postsecondary"]'::jsonb, '["university","adult_study"]'::jsonb, '{"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"disability":false,"student":true,"elderly":false,"tags":["student","postsecondary","loan"]}'::jsonb, null) on conflict (id) do nothing;
