insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('88888888-8888-8888-8888-888888888888', 'old-age-allowance', '高齡津貼（生果金）', 'Old Age Allowance (OAA)', '社會福利署（社會保障）', 'social_security', '俾 70 歲或以上長者嘅每月現金津貼，唔使入息審查。金額每年由政府公布。', '70 歲或以上嘅香港長者。', '俾 70 歲或以上長者嘅每月現金津貼，唔使入息審查。金額每年由政府公布。', '70 歲或以上嘅香港長者。', '未夠 70 歲，或已領取長者生活津貼 / 綜援嘅長者。', '["年滿 70 歲","成為香港居民滿 7 年，並在申請前連續居港滿 1 年（1 年內離港不超過 90 日視為居港）","毋須入息或資產審查（免審查）","並非同時領取長者生活津貼、傷殘津貼或綜援","領款期間須繼續居於香港；被羈押或入住懲教院所期間不可領取"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssa_app/index.html', null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssaec/ssaec_oaa/index.html', 'https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssaec/ssaec_oaa/index.html', '2026-06-01', 'verified', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["elderly"]'::jsonb, '[{"order":1,"text":"第一步：睇下你係咪夠 70 歲。"},{"order":2,"text":"第二步：準備身份證同銀行戶口資料。"},{"order":3,"text":"第三步：填高齡津貼申請表。"},{"order":4,"text":"第四步：交俾社會福利署。"},{"order":5,"text":"第五步：批咗會每月過錢入你戶口。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"age_proof","label":"年齡證明（身份證）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssa_app/index.html"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/tc/pubsvc/socsecu/ssallowance/ssaec/ssaec_oaa/index.html","title":"高齡津貼（生果金） 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["retirement"]'::jsonb, '{"requiresElderly":true,"minAgeBand":"70_plus","excludeIfCssa":true,"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":70,"disability":false,"student":false,"elderly":true,"tags":["elderly"]}'::jsonb, 'old_age_allowance.md') on conflict (id) do nothing;
