insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('dddddddd-dddd-dddd-dddd-dddddddddddd', 'personal-emergency-link', '平安鐘（個人緊急召援服務）', 'Personal Emergency Link Service', '社會福利署（服務由長者安居協會等營運）', 'elderly', '喺屋企裝一個緊急按鈕，長者一撳就有 24 小時服務中心幫手，遇到跌倒、唔舒服或危險可以即刻求助。有需要嘅長者可獲政府 / 關愛基金資助費用。', '獨居或日間獨自在家、想有多份安全保障嘅長者及殘疾人士。', '喺屋企裝一個緊急按鈕，長者一撳就有 24 小時服務中心幫手，遇到跌倒、唔舒服或危險可以即刻求助。有需要嘅長者可獲政府 / 關愛基金資助費用。', '獨居或日間獨自在家、想有多份安全保障嘅長者及殘疾人士。', '屋企長時間有人照顧、唔需要緊急召援嘅人士。', '["對象為獨居或缺乏照顧、有需要嘅長者及殘疾人士，提供 24 小時緊急支援","綜援緊急召援系統津貼：領綜援並年滿 65 歲、獨居或家人未能照顧者；或 60–64 歲經證明超過 50% 殘疾／有特定醫療情況者","資助計劃：由地區「關愛隊」識別及轉介嘅獨居／雙老長者及殘疾人士（限指定地區）","部分經濟有困難人士可獲政府／關愛基金資助服務費用","由認可服務機構（如長者安居協會）營運；詳細申請條件以官方及服務機構為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.schsa.org.hk/tc/', null, null, null, null, null, '2338 8312', null, 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/', 'https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["elderly","disability"]'::jsonb, '[{"order":1,"text":"第一步：睇下你係咪獨居或日頭自己一個喺屋企。"},{"order":2,"text":"第二步：聯絡長者安居協會或你區嘅長者中心。"},{"order":3,"text":"第三步：如經濟有困難，同時申請費用資助。"},{"order":4,"text":"第四步：職員上門幫你安裝平安鐘。"},{"order":5,"text":"第五步：有事撳掣，24 小時服務中心即刻幫你。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"age_proof","label":"年齡證明（身份證）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"入息證明","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.schsa.org.hk/tc/"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/tc/pubsvc/elderly/cat_commcare/","title":"平安鐘（個人緊急召援服務） 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["long_term_care","retirement"]'::jsonb, '{"requiresElderly":true,"minAgeBand":"60_64","meansTested":false,"boostLivingAlone":true}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":60,"disability":true,"student":false,"elderly":true,"tags":["elderly","disability"]}'::jsonb, 'personal_emergency_link.md') on conflict (id) do nothing;
