insert into public.benefit_life_events (benefit_id, life_event_code) values ('c1000000-0000-0000-0000-000000000002', 'low_income') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb', 'public-transport-subsidy', '公共交通費用補貼 / $2 乘車優惠', 'Public Transport Fare Subsidy / $2 Concessionary Fares', '勞工及福利局 / 運輸署', 'elderly', '$2 乘車優惠俾長者及合資格殘疾人士用優惠票價搭車船；公共交通費用補貼則幫返交通開支較高嘅市民。詳情及年齡以官方為準。', '長者、合資格殘疾人士，或每月交通開支較高嘅市民。', '$2 乘車優惠俾長者及合資格殘疾人士用優惠票價搭車船；公共交通費用補貼則幫返交通開支較高嘅市民。詳情及年齡以官方為準。', '長者、合資格殘疾人士，或每月交通開支較高嘅市民。', '不符合年齡 / 殘疾資格，而交通開支又唔高嘅人士。', '["$2 優惠：年滿 60 歲香港居民；或 60 歲以下、領綜援並評定為 100% 傷殘或領取傷殘津貼嘅殘疾人士","$2 優惠：長者須用樂悠咭、殘疾人士須用載有「殘疾人士身分」嘅個人八達通（現金或匿名長者八達通不適用）","$2 優惠不設入息審查，屬普及性優惠","公共交通費用補貼：任何市民不論年齡及入息，每月公共交通開支超出門檻即可受惠，無須申請","$2 優惠票價安排將於 2026 年 4 月 3 日起調整為「$2 劃一或 8 折」，以官方為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.ptfss.gov.hk/tc-main.html', null, null, null, null, null, '187 2333', null, 'https://www.td.gov.hk/tc/gov_public_transport_fare_concession/index.html', 'https://www.td.gov.hk/tc/gov_public_transport_fare_concession/index.html', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["elderly","disability","low_income"]'::jsonb, '[{"order":1,"text":"第一步：睇下你係咪長者或合資格殘疾人士。"},{"order":2,"text":"第二步：申請 / 使用個人八達通或樂悠咭。"},{"order":3,"text":"第三步：搭車船時嘟卡，自動用優惠票價。"},{"order":4,"text":"第四步：交通費補貼會按你嘅實際車費計算。"},{"order":5,"text":"第五步：補貼會經指定途徑發放（詳情睇官方）。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"age_proof","label":"年齡證明（身份證）","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.ptfss.gov.hk/tc-main.html"}]'::jsonb, '[{"url":"https://www.td.gov.hk/tc/gov_public_transport_fare_concession/index.html","title":"公共交通費用補貼 / $2 乘車優惠 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["retirement","disability_diagnosed"]'::jsonb, '{"travelRelated":true,"meansTested":false,"boostLivingAlone":true}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"age_min":null,"disability":true,"student":false,"elderly":true,"tags":["elderly","disability","low_income"]}'::jsonb, 'public_transport_subsidy.md') on conflict (id) do nothing;
