insert into public.benefit_life_events (benefit_id, life_event_code) values ('d2000000-0000-0000-0000-000000000007', 'retirement') on conflict do nothing;
insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-000000000009', 'salaries-tax-allowances-deductions', '薪俸稅免稅額及扣除', 'Salaries Tax Allowances and Deductions', '稅務局', 'tax', '透過薪俸稅 / 個人入息課稅下嘅免稅額及可扣除項目，減低應繳稅款。此為稅務寬減，並非現金津貼。', '須繳交薪俸稅或選擇個人入息課稅、並符合各項免稅額 / 扣除條件嘅納稅人。', '薪俸稅及個人入息課稅設有多項免稅額及可扣除項目，用以減低應繳稅款（屬稅務寬減，並非現金發放）。免稅額包括：基本免稅額、已婚人士免稅額、子女免稅額、供養父母 / 祖父母免稅額、單親免稅額、傷殘受養人免稅額、傷殘人士免稅額、供養兄弟姊妹免稅額。可扣除項目包括：認可慈善捐款、強積金強制性供款、個人進修開支、居所貸款利息、住宅租金扣除、長者住宿照顧開支、自願醫保計劃（VHIS）合資格保費、合資格延期年金保費及可扣稅強積金自願性供款、輔助生育服務開支等。以上項目透過填報周年報稅表（個別人士 BIR60）相關部分申索。', '有薪俸收入或選擇個人入息課稅、並符合相關免稅額 / 扣除條件嘅人士。', '並非現金津貼；不能減低稅款以外嘅開支；不符合個別免稅額 / 扣除條件者不能申索該項。', '["須為薪俸稅納稅人，或選擇以個人入息課稅方式評稅","免稅額：基本、已婚人士、子女、供養父母 / 祖父母、單親、傷殘受養人、傷殘人士、供養兄弟姊妹（各設個別條件）","扣除項目：認可慈善捐款、強積金強制性供款、個人進修開支、居所貸款利息、住宅租金、長者住宿照顧開支、自願醫保保費、合資格延期年金及可扣稅強積金自願性供款、輔助生育服務開支等","透過周年報稅表（個別人士 BIR60）相關部分填報及申索，並保留有關證明文件備查","⚠️ Needs Manual Review：各項免稅額 / 扣除上限金額、適用課稅年度及詳細條件以稅務局最新公布為準"]'::jsonb, null, null, null, null, null, null, null, null, null, null, null, null, null, null, null, '187 8088', null, 'https://www.ird.gov.hk/eng/tax/ind_ctr.htm', 'https://www.ird.gov.hk/eng/tax/ind_ctr.htm', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["other"]'::jsonb, '[{"order":1,"text":"第一步：了解你可能符合嘅免稅額及可扣除項目。"},{"order":2,"text":"第二步：收齊相關證明文件（收據、供款 / 租金證明等）。"},{"order":3,"text":"第三步：填寫周年報稅表（個別人士 BIR60）相關部分申索。"},{"order":4,"text":"第四步：遞交報稅表；保留證明文件以備稅務局查核。"}]'::jsonb, '[{"label":"周年報稅表（個別人士 BIR60）","required":true},{"label":"相關證明 / 收據（如捐款收據、租金證明、供款證明等，備查）","required":false}]'::jsonb, '[]'::jsonb, '[{"url":"https://www.ird.gov.hk/eng/tax/ind_ctr.htm","title":"稅務局 — 免稅額、扣除及稅率表（官方頁面）","titleZh":"稅務局 — 免稅額、扣除及稅率表","titleEn":"IRD — Allowances, Deductions and Tax Rate Table","publisher":"Inland Revenue Department","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["marriage","new_baby","retirement"]'::jsonb, '{"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"disability":false,"student":false,"elderly":false,"tags":["tax","tax_relief","allowances","deductions"]}'::jsonb, null) on conflict (id) do nothing;
