insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('11111111-1111-1111-1111-111111111111', 'school-textbook-assistance', '學校書簿津貼計劃', 'School Textbook Assistance Scheme', '在學資助處（學生資助處）', 'student_assistance', '幫低收入家庭俾返書簿同部分學習雜費。合資格學生可以攞全額或半額津貼。', '就讀小學或中學、家庭收入較低嘅學生。', '幫低收入家庭俾返書簿同部分學習雜費。合資格學生可以攞全額或半額津貼。', '就讀小學或中學、家庭收入較低嘅學生。', '正領取綜援嘅家庭（綜援已包學校相關津貼，唔需要重複申請）。', '["學生就讀本地小學或中學全日制日校","申請人為學生嘅家長或監護人","學生為未婚香港居民，並在港有居留權／入境權，或不受逗留條件限制嘅居留許可","家庭須通過學生資助處入息審查（按「經調整家庭收入」計算，分全額或半額）","並非正領取綜援（綜援家庭嘅書簿等開支由社署直接支付，毋須重複申請）","持訪客簽證、雙程證、學生簽證或其受養人不合資格"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/procedures.php', null, null, null, null, null, '2802 2345', null, 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/overview.php', 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/overview.php', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["student","low_income"]'::jsonb, '[{"order":1,"text":"第一步：先睇你屋企有冇讀緊小學或中學嘅學生。"},{"order":2,"text":"第二步：準備身份證、學生證明、住址證明、收入證明。"},{"order":3,"text":"第三步：填學生資助處「學生資助計劃」綜合申請表。"},{"order":4,"text":"第四步：連同文件副本郵寄或網上交俾學生資助處。"},{"order":5,"text":"第五步：等政府審查，再睇通知書知結果同金額。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"student_id","label":"學生身份證 / 出世紙","required":true},{"key":"student_proof","label":"學生證明（學校信 / 收生紙）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"入息證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/procedures.php"}]'::jsonb, '[{"url":"https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/overview.php","title":"學校書簿津貼計劃 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["primary_school","secondary_school","low_income"]'::jsonb, '{"gradeLevels":["primary","secondary"],"maxIncomeBand":"20k_30k","excludeIfCssa":true,"boostSingleParent":true,"boostNewArrival":true}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":false,"age_min":null,"disability":false,"student":true,"elderly":false,"tags":["student","low_income"]}'::jsonb, 'textbook_assistance.md') on conflict (id) do nothing;
