insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('22222222-2222-2222-2222-222222222222', 'student-travel-subsidy', '學生車船津貼計劃', 'Student Travel Subsidy Scheme', '在學資助處（學生資助處）', 'student_assistance', '幫住得遠、要搭車返學嘅低收入學生，補貼部分車船交通費。', '需要搭車船返學、屋企收入較低嘅學生。', '幫住得遠、要搭車返學嘅低收入學生，補貼部分車船交通費。', '需要搭車船返學、屋企收入較低嘅學生。', '住喺學校附近、唔使付車費，或可步行返學嘅學生。', '["學生就讀屬車船津貼類別嘅學校（中小學，或認可院校全日制第一學位以下課程）","申請人為學生嘅家長或監護人；學生為未婚香港居民並具香港居留身份（須附證明）","住所距離學校超過 10 分鐘步行路程，並須以公共交通工具返學","家庭須通過學生資助處入息審查","並非正領取綜援（綜援家庭嘅交通費由社署支付）；夜校學生不適用"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/procedures.php', null, null, null, null, null, '2802 2345', null, 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/overview.php', 'https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/overview.php', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["student","low_income"]'::jsonb, '[{"order":1,"text":"第一步：睇下個學生係咪要搭車船先返到學校。"},{"order":2,"text":"第二步：準備身份證、學生證明、住址證明、收入證明。"},{"order":3,"text":"第三步：填學生資助處「學生資助計劃」申請表。"},{"order":4,"text":"第四步：交俾學生資助處。"},{"order":5,"text":"第五步：等通知，批咗就會過數入你銀行戶口。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"student_id","label":"學生身份證 / 出世紙","required":true},{"key":"student_proof","label":"學生證明（學校信 / 收生紙）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"入息證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/procedures.php"}]'::jsonb, '[{"url":"https://www.wfsfaa.gov.hk/tc/sfo/primarysecondary/tt/overview.php","title":"學生車船津貼計劃 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["primary_school","secondary_school","university","low_income"]'::jsonb, '{"gradeLevels":["primary","secondary","tertiary"],"maxIncomeBand":"20k_30k","travelRelated":true,"boostSingleParent":true,"boostNewArrival":true}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":false,"age_min":null,"disability":false,"student":true,"elderly":false,"tags":["student","low_income"]}'::jsonb, 'travel_subsidy.md') on conflict (id) do nothing;
