insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('d2000000-0000-0000-0000-000000000006', 'traffic-accident-victims-assistance', '交通意外傷亡援助計劃', 'Traffic Accident Victims Assistance (TAVA) Scheme', '社會福利署（社會保障）', 'social_security', '為道路交通意外傷者，或交通意外死者嘅在世受養人，提供「無須經濟審查」嘅經濟援助，無論意外責任誰屬。', '香港道路交通意外嘅傷者，或意外中死者嘅在世受養人。', '交通意外傷亡援助計劃（TAVA）為道路交通意外傷者或死者在世受養人提供無須經濟審查嘅現金援助，不論意外責任誰屬。申請須於意外發生後 6 個月內提出；傷者於意外發生時須合法獲准留港；並須因意外死亡、永久傷殘，或由註冊醫生 / 註冊中醫師證明因傷須住院或病假不少於 7 天。計劃只援助人身傷亡，不包括財物損失。', '香港道路交通意外傷者，或意外死者嘅在世受養人（無須經濟審查）。', '財物損失（不屬援助範圍）；意外發生時非合法留港者；逾 6 個月申請期者。', '["傷者於交通意外發生時須合法獲准留港","須於意外發生日期後 6 個月內提出申請","傷者因意外死亡或永久傷殘；或所受傷勢經註冊醫生 / 註冊中醫師證明須住院或病假不少於 7 天","屬「無須經濟審查」計劃，不論導致意外嘅責任誰屬","只援助人身傷亡，不包括財物損失或損毀","⚠️ Needs Manual Review：援助金額及各項細則以社會福利署最新公布及《交通意外傷亡援助計劃》單張為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.sssof.swd.gov.hk/eForm/eApplyTAVA/Start?lang=en_US', null, null, null, null, null, '2343 2255', null, 'https://www.swd.gov.hk/en/pubsvc/socsecu/trafficacc/', 'https://www.swd.gov.hk/en/pubsvc/socsecu/trafficacc/', '2026-07-23', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["other","disability"]'::jsonb, '[{"order":1,"text":"第一步：確認意外發生於 6 個月內，並準備意外及傷勢證明。"},{"order":2,"text":"第二步：填寫 TAVA 申請表（社署網上初步申請表或紙本表格）。"},{"order":3,"text":"第三步：連同醫生／中醫證明及意外證明遞交社會福利署。"},{"order":4,"text":"第四步：接受社署審核。"},{"order":5,"text":"第五步：批核後領取援助金。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"label":"醫生 / 中醫證明書（住院或病假證明）","required":true},{"label":"交通意外證明（如警方報告 / 意外記錄）","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true}]'::jsonb, '[{"name":"TAVA 網上初步申請表","type":"link","url":"https://www.sssof.swd.gov.hk/eForm/eApplyTAVA/Start?lang=en_US"}]'::jsonb, '[{"url":"https://www.swd.gov.hk/en/pubsvc/socsecu/trafficacc/","title":"交通意外傷亡援助計劃（官方頁面）","titleZh":"交通意外傷亡援助計劃","titleEn":"Traffic Accident Victims Assistance Scheme","publisher":"Social Welfare Department","sourceType":"official_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.swd.gov.hk/storage/asset/section/179/en/TAVA_Brief_Eng_201403.pdf","title":"交通意外傷亡援助計劃 — 簡介（官方單張）","titleZh":"交通意外傷亡援助計劃簡介","titleEn":"TAVA Scheme Brief","publisher":"Social Welfare Department","sourceType":"guidance_note","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"},{"url":"https://www.sssof.swd.gov.hk/eForm/eApplyTAVA/Start?lang=en_US","title":"TAVA 網上初步申請表（官方申請頁面）","titleZh":"TAVA 網上初步申請表","titleEn":"TAVA Preliminary Application Form","publisher":"Social Welfare Department","sourceType":"application_page","retrievedAt":"2026-07-23","lastCheckedAt":"2026-07-23","status":"active"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["disability-allowance"]'::jsonb, '["hospital_discharge","disability_diagnosed"]'::jsonb, '{"meansTested":false}'::jsonb, '{"means_tested":false,"income_tested":false,"asset_tested":false,"disability":true,"student":false,"elderly":false,"tags":["social_security","accident","injury","non_means_tested"]}'::jsonb, null) on conflict (id) do nothing;
