insert into public.benefits (id, slug, name_zh, name_en, department, category_code, purpose, target_beneficiaries, summary, suitable_for, not_suitable_for, eligibility, means_test, residency_requirement, income_requirement, asset_requirement, age_requirement, employment_requirement, student_requirement, application_method, online_url, form_url, guidance_url, faq_url, processing_time, renewal, appeal, contact_phone, contact_email, official_url, source_url, last_updated, status, active, disclaimer, audience, steps, documents, forms, sources, faq, rules, related_slugs, life_events, match_rule, facets, knowledge_doc) values ('66666666-6666-6666-6666-666666666666', 'working-family-allowance', '在職家庭津貼計劃', 'Working Family Allowance Scheme', '在職家庭津貼辦事處', 'employment', '幫有人返工但收入唔高嘅家庭。除咗家庭津貼，仲有兒童津貼幫補在學子女開支。', '有家庭成員返工、收入唔高、又有在學子女嘅家庭。', '幫有人返工但收入唔高嘅家庭。除咗家庭津貼，仲有兒童津貼幫補在學子女開支。', '有家庭成員返工、收入唔高、又有在學子女嘅家庭。', '正領取綜援嘅家庭（綜援同在職家庭津貼唔可以同時領取）。', '["住戶並非領取綜援（綜援與職津不可同時領取）","住戶有成員從事有薪工作並達到每月工時要求","住戶每月收入及資產不超過指定上限（設不同津貼級別）","設兒童津貼，補助合資格在學或年幼子女","住戶成員一般須為香港居民並通常居於香港","工時門檻、入息上限及金額每年公布，以官方最新資料為準"]'::jsonb, null, null, null, null, null, null, null, null, null, 'https://www.wfsfaa.gov.hk/wfao/tc/application/forms.htm', null, null, null, null, null, '2558 3000', null, 'https://www.wfsfaa.gov.hk/wfao/tc/index.htm', 'https://www.wfsfaa.gov.hk/wfao/tc/index.htm', '2026-06-01', 'needs_review', true, '本系統只幫你整理資料及估計，不代表政府已批准申請。最終批核以政府部門公佈為準。請以官方連結最新資料為準。', '["low_income"]'::jsonb, '[{"order":1,"text":"第一步：睇下屋企有冇人返緊工，又有冇在學子女。"},{"order":2,"text":"第二步：準備身份證、入息證明、工時證明、住址證明。"},{"order":3,"text":"第三步：填在職家庭津貼申請表。"},{"order":4,"text":"第四步：交俾在職家庭津貼辦事處。"},{"order":5,"text":"第五步：等通知，批咗會按月或一筆過過數。"}]'::jsonb, '[{"key":"applicant_id","label":"申請人身份證","required":true},{"key":"student_id","label":"學生身份證 / 出世紙","required":true},{"key":"student_proof","label":"學生證明（學校信 / 收生紙）","required":true},{"key":"address_proof","label":"住址證明","required":true},{"key":"income_proof","label":"入息證明","required":true},{"key":"bank_account","label":"銀行戶口資料","required":true},{"key":"tenancy_agreement","label":"租單 / 租約（如適用）","required":true}]'::jsonb, '[{"name":"申請表 / 申請方式","type":"link","url":"https://www.wfsfaa.gov.hk/wfao/tc/application/forms.htm"}]'::jsonb, '[{"url":"https://www.wfsfaa.gov.hk/wfao/tc/index.htm","title":"在職家庭津貼計劃 官方頁面"}]'::jsonb, '[]'::jsonb, '[]'::jsonb, '[]'::jsonb, '["low_income","job_seeking"]'::jsonb, '{"maxIncomeBand":"30k_40k","excludeIfCssa":true,"boostSingleParent":true,"boostNewArrival":true}'::jsonb, '{"means_tested":true,"income_tested":true,"asset_tested":false,"age_min":null,"disability":false,"student":false,"elderly":false,"tags":["low_income"]}'::jsonb, 'working_family_allowance.md') on conflict (id) do nothing;
